export function hasVirtualAsset(path: string): boolean {
  return path in VIRTUAL_ASSETS;
}

export function readVirtualAsset(path: string): string {
  if (path in VIRTUAL_ASSETS) {
    return VIRTUAL_ASSETS[path];
  }
  throw new Error(`Virtual asset not found: ${path}`);
}

export function listVirtualAssets(prefix: string): string[] {
  return Object.keys(VIRTUAL_ASSETS).filter(p => p.startsWith(prefix));
}
